-- Enum for employee roles\nCREATE TYPE employee_role AS (\n    manager,\n    staff,\n    intern\n);\n\n-- Enum for employment statuses\nCREATE TYPE employment_status AS (\n    active,\n    inactive,\n    terminated\n);\n\n-- Table for departments\nCREATE TABLE departments (\n    id SERIAL PRIMARY KEY,\n    name VARCHAR(255) NOT NULL UNIQUE,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP\n);\n\n-- Table for employees\nCREATE TABLE employees (\n    id SERIAL PRIMARY KEY,\n    name VARCHAR(255) NOT NULL,\n    role employee_role NOT NULL,\n    status employment_status NOT NULL,\n    department_id INT,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,\n    FOREIGN KEY (department_id) REFERENCES departments(id) ON DELETE SET NULL\n);\n\n-- Creating indexes for optimization\nCREATE INDEX idx_employees_name ON employees(name);\nCREATE INDEX idx_employees_status ON employees(status);\nCREATE INDEX idx_departments_name ON departments(name);\n\n-- Sample data insertion for departments\nINSERT INTO departments (name) VALUES (\n    'Human Resources',\n    'Engineering',\n    'Sales'\n);\n\n-- Sample data insertion for employees\nINSERT INTO employees (name, role, status, department_id) VALUES (\n    ('Alice Smith', 'manager', 'active', 1),\n    ('Bob Johnson', 'staff', 'active', 2),\n    ('Charlie Brown', 'intern', 'inactive', 1)\n);\n